export const angularQA = [
  // BEGINNER (20)
  { level: 'basic', q: 'What is an Angular module (NgModule)?', a: 'An NgModule is a construct that gathers together components, directives, pipes, and services into cohesive blocks of functionality. Note: In modern Angular (v14+), Standalone Components reduce the need for NgModules.' },
  { level: 'basic', q: 'Why did Angular shift to Standalone Components?', a: 'To reduce boilerplate, simplify the learning curve, and make lazy-loading and tree-shaking more efficient by removing the NgModule abstraction layer.' },
  { level: 'basic', q: 'What is a decorator in Angular?', a: 'A decorator is a function that adds metadata to a class, its members, or its method arguments. Examples: @Component(), @Injectable(), @Input().' },
  { level: 'basic', q: 'What are the main building blocks of Angular?', a: 'Components, Templates, Directives, Pipes, Routing, and Services/Dependency Injection.' },
  { level: 'basic', q: 'What is string interpolation?', a: 'A way to bind a component property to a template, using double curly braces: `{{ propertyName }}`.' },
  { level: 'basic', q: 'What is property binding?', a: 'Binding a component property to a DOM property using square brackets: `[hidden]="isHidden"`.' },
  { level: 'basic', q: 'What is event binding?', a: 'Listening to DOM events and executing a component method using parentheses: `(click)="save()"`.' },
  { level: 'basic', q: 'What is two-way data binding?', a: 'A combination of property and event binding that syncs data between the component and the view. Uses the banana-in-a-box syntax: `[(ngModel)]="name"`.' },
  { level: 'basic', q: 'What is the purpose of the AppRoot component?', a: 'Usually `<app-root>`, it is the top-level component that bootstraps the application and holds the router outlet.' },
  { level: 'basic', q: 'What is angular.json?', a: 'The CLI configuration file containing workspace and project-specific settings for building, serving, test, and linting.' },
  { level: 'basic', q: 'What is the package.json file?', a: 'An npm/node standard file that defines script commands and lists the libraries (dependencies) that the project needs to run.' },
  { level: 'basic', q: 'What is a pipe in Angular?', a: 'A function that takes in data as input and transforms it to a desired output format in the template. Example: `{{ date | date:"shortDate" }}`.' },
  { level: 'basic', q: 'What is ng-template?', a: 'An Angular element for rendering HTML. It is never displayed directly. It is typically used with structural directives (like *ngIf or *ngFor) which instantiate it.' },
  { level: 'basic', q: 'What is ng-container?', a: 'A logical container that does not render an extra element in the DOM. Extremely useful when you need to apply a structural directive (*ngIf) without wrapping the content in a <div>.' },
  { level: 'basic', q: 'How do you structure an Angular project?', a: 'Typically using a feature-based structure: Core folder (singletons), Shared folder (dumb components/pipes), and Feature folders (smart components and routing).' },
  { level: 'basic', q: 'What is the Angular CLI?', a: 'A command-line interface tool to initialize, develop, scaffold, and maintain Angular applications.' },
  { level: 'basic', q: 'How do you create a component using the CLI?', a: '`ng generate component my-comp` or `ng g c my-comp`.' },
  { level: 'basic', q: 'What is an environment file?', a: 'Used to store configuration variables targeting specific environments (like dev, staging, prod), swapped automatically during the build process.' },
  { level: 'basic', q: 'What is the ngOnInit lifecycle hook?', a: 'A lifecycle hook that runs once after the first ngOnChanges. It is the best place to initialize data and make the first API calls.' },
  { level: 'basic', q: 'What is the ngOnDestroy hook?', a: 'Runs right before the component is destroyed. This is critical for cleaning up things like RxJS subscriptions to prevent memory leaks.' },

  // NGRX & STATE MANAGEMENT (15)
  { level: 'advanced', q: 'What is NgRx?', a: 'A reactive State Management library for Angular inspired by Redux, utilizing RxJS heavily.' },
  { level: 'advanced', q: 'What is an NgRx Store?', a: 'A single, immutable data structure that represents the state of your entire application.' },
  { level: 'advanced', q: 'What is an NgRx Action?', a: 'An object describing an event that has happened in the application, dispatched to the store. Created via `createAction`.' },
  { level: 'advanced', q: 'What is an NgRx Reducer?', a: 'A pure function that takes the current state and a dispatched Action, and returns a new updated state object.' },
  { level: 'advanced', q: 'What is an NgRx Selector?', a: 'Pure functions used for obtaining slices of store state. They memorize (cache) previous results for performance.' },
  { level: 'advanced', q: 'What are NgRx Effects?', a: 'A side effect model. They listen for actions dispatched from the store, perform operations (like API calls), and then dispatch new actions.' },
  { level: 'advanced', q: 'What is the NgRx Entity pattern?', a: 'A utility to manage collections of entities (lists of objects). It provides an adapter with CRUD operations and normalizes data into an `{ ids: [], entities: {} }` structure for rapid lookups.' },
  { level: 'advanced', q: 'What is NgRx SignalStore?', a: 'A lightweight, fully functional state management solution built on Angular Signals. It requires no Actions or Reducers boilerplate and is the modern approach for local or global state in v17+.' },
  { level: 'intermediate', q: 'When should you use Global State vs Local State?', a: 'Use Global (NgRx Store) for data shared across multiple distant components, user sessions, or cached API results. Use Local (ComponentStore/SignalStore) for data specific to a feature module or complex component.' },
  { level: 'advanced', q: 'How do you handle loading/error states in NgRx?', a: 'Typically by defining three distinct actions: `loadEntities`, `loadEntitiesSuccess`, and `loadEntitiesFailure`. The reducer updates `isLoading` and `error` flags accordingly.' },
  { level: 'intermediate', q: 'What is the facade pattern in Angular component state?', a: 'A service that injects the Store and provides selected Observables/Signals and methods to dispatch actions. This hides NgRx complexity from the "dumb" UI components.' },
  { level: 'advanced', q: 'How does time-travel debugging work in Redux/NgRx?', a: 'Since the store state is immutable, every action creates a new snapshot. The Redux DevTools extension allows you to rewind and jump between these immutable state snapshots.' },
  { level: 'advanced', q: 'What happens if a reducer is not a pure function?', a: 'The state could mutate in place, leading to unpredictable bugs and preventing Angular from knowing if the state reference changed (breaking OnPush change detection).' },
  { level: 'advanced', q: 'What is the difference between switchMap and concatMap inside NgRx Effects?', a: '`switchMap` cancels the previous inner observable if a new action arrives (good for GET requests/search). `concatMap` queues the inner observables in order (good for POST/PUT requests where order matters).' },
  { level: 'expert', q: 'How do you test NgRx code?', a: 'Reducers and Selectors are tested as pure functions. Effects are tested using `provideMockActions` and jasmine marbles (hot/cold observables). Components are tested by mocking the Store via `provideMockStore`.' },

  // TESTING (15)
  { level: 'intermediate', q: 'What is the Angular TestBed?', a: 'A powerful unit testing utility that configures and initializes the environment for writing unit tests, creating a dynamic module for the component context.' },
  { level: 'intermediate', q: 'What is describe, beforeAll, beforeEach, it in Jasmine?', a: '`describe` groups tests. `it` defines a specific test. `beforeEach` runs setup code before EVERY test in the block. `beforeAll` runs setup code ONCE for the block.' },
  { level: 'advanced', q: 'What is MockComponent and why use it?', a: 'A dummy version of a child component used to isolate the parent component being tested. It prevents the test from failing due to child dependencies.' },
  { level: 'advanced', q: 'How do you test services with HTTP dependencies?', a: 'By injecting the `HttpTestingController` (via `provideHttpClientTesting()`). You can expect requests, flush them with mock data, and verify no outstanding requests remain.' },
  { level: 'advanced', q: 'What are Component Harnesses?', a: 'A concept from Angular CDK testing. It provides a robust API for interacting with components (like MatSelect) without relying on fragile CSS DOM selectors.' },
  { level: 'intermediate', q: 'What is a Spy in Jasmine/Jest?', a: 'A mocked function that tracks information about if and how it was called (arguments, call count) and allows you to fake its return value (`spyOn(obj, "method").and.returnValue()`).' },
  { level: 'advanced', q: 'How do you test a component with OnPush change detection?', a: 'Since `fixture.detectChanges()` might not work if inputs haven\'t changed, you often have to simulate the event or call `fixture.componentRef.setInput()` in newer Angular versions.' },
  { level: 'intermediate', q: 'What is the difference between fixture.debugElement and fixture.nativeElement?', a: '`nativeElement` provides the raw DOM element. `debugElement` is an Angular wrapper that provides access to the component instance, directives, and custom query predicates (`By.css`).' },
  { level: 'advanced', q: 'How do you test Angular Signals?', a: 'Since signals are synchronous and pull-based, you simply set the signal (`mySignal.set(val)`) and assert the computed value or template output immediately after `detectChanges()`.' },
  { level: 'advanced', q: 'What is the fakeAsync zone?', a: 'It allows you to test asynchronous code (like `setTimeout` or Promises) in a synchronous way, by letting you manually advance time using `tick(ms)` or `flush()`, avoiding flaky asynchronous tests.' },
  { level: 'advanced', q: 'What is the difference between tick() and flush()?', a: '`tick(ms)` advances the virtual clock by a specific amount of time. `flush()` advances time until the macrotask queue is completely empty.' },
  { level: 'intermediate', q: 'How do you test an Angular Route Guard?', a: 'Extract the functional guard or class injectables into the test file, provide any required mock services (like AuthService), call the guard function directly, and check if it returns true, false, or a UrlTree.' },
  { level: 'intermediate', q: 'Why is NO_ERRORS_SCHEMA considered an anti-pattern?', a: 'It tells the compiler to ignore unrecognized elements and attributes. While it suppresses errors for missing child components, it also masks genuine typos (e.g., `<app-utten>` instead of `<app-button>`).' },
  { level: 'advanced', q: 'How do you test un-exported functions or private component states?', a: 'You shouldn\'t. Tests should verify the public API and observable side effects (DOM output, service calls) rather than brittle internal implementation details.' },
  { level: 'expert', q: 'How do you mock the router in tests?', a: 'Use `provideRouter([])` with an empty config, or inject a mock object for `Router` via `provide({provide: Router, useValue: mockRouter})` and spy on its `navigate` or `navigateByUrl` methods.' },

  // ADVANCED ARCHITECTURE AND INTERNALS (30)
  { level: 'expert', q: 'What is the Angular Compiler (Ivy)?', a: 'Ivy is the rendering engine in modern Angular. It compiles components into highly efficient DOM instructions at build time, significantly reducing bundle size.' },
  { level: 'expert', q: 'What are tree-shakable providers (`providedIn: root`)?', a: 'By providing a service in `root`, Angular does not need it registered in any module. If the service is never injected anywhere, the bundler can safely drop its code from the final payload.' },
  { level: 'expert', q: 'Explain Zone.js and its role in Angular.', a: 'Zone.js monkeys-patches standard async browser APIs (setTimeout, XHR, DOM events). When an async task completes, Zone.js tells Angular, which then triggers change detection from top to bottom (unless OnPush).' },
  { level: 'expert', q: 'What does "Zone-less Angular" mean?', a: 'In Angular 18+, with Signals and the `provideExperimentalZonelessChangeDetection()` API, Angular no longer needs Zone.js. It precisely tracks exactly which DOM nodes need updating via tracking signals.' },
  { level: 'expert', q: 'What is hydration vs destratification in SSR?', a: 'Hydration is attaching event listeners and state to server-rendered HTML. Angular 16 introduced Non-Destructive Hydration, which no longer destroys the DOM before recreating it.' },
  { level: 'advanced', q: 'What is control flow migration in Angular 17?', a: 'Moving from structural directives (`*ngIf`, `*ngFor`) to built-in template syntax (`@if`, `@for`). It compiles much faster, performs better, and requires no module imports.' },
  { level: 'advanced', q: 'What is Deferrable Views (`@defer`)?', a: 'A declarative way to lazy-load components directly in the template. `@defer (on viewport) { <heavy-chart /> }` will chunk the chart component and only load it when it scrolls into view.' },
  { level: 'advanced', q: 'What are esbuild and Vite doing in Angular 17+?', a: 'Webpack was replaced. Esbuild compiles JS/TS blazingly fast. Vite serves the local dev server using native ES modules for immediate updates without rebundling the whole app.' },
  { level: 'expert', q: 'What is a forwardRef and when do you need it?', a: 'A function that allows referencing a class before it has been fully defined. It\'s required when a class injects a service that is declared later in the file, or when a component implements `ControlValueAccessor` and provides itself.' },
  { level: 'expert', q: 'What is the Angular Injector hierarchy?', a: 'Angular has two injector trees: The ModuleInjector hierarchy (`@Injectable({providedIn: root/module})`) and the ElementInjector hierarchy (providers on the `@Component()` or `@Directive()`). Resolution starts at the Element and falls back to the Module.' },
  { level: 'advanced', q: 'Describe how `HostListener` and `HostBinding` work.', a: '`@HostListener` binds to an event on the host element of the component/directive. `@HostBinding` binds a property of the class to an attribute/class/style of the host element.' },
  { level: 'expert', q: 'What is Dependency Injection Token (InjectionToken)?', a: 'A token used to inject non-class dependencies like string configs, interfaces, or plain objects into constructors because interfaces disappear at runtime in TypeScript.' },
  { level: 'advanced', q: 'How does Angular handle XSS attacks?', a: 'Angular considers all values untrusted and automatically sanitizes values depending on the context: HTML (escapes script tags), Style (blocks dangerous CSS), and URLs (prevents javascript: URIs).' },
  { level: 'advanced', q: 'How do you bypass Angular sanitization?', a: 'By injecting the `DomSanitizer` service and calling `bypassSecurityTrustHtml()`, `bypassSecurityTrustUrl()`, or `bypassSecurityTrustResourceUrl()`. Use sparingly!' },
  { level: 'advanced', q: 'What is the difference between ViewChild and ContentChild?', a: '`@ViewChild` accesses elements/components defined in the component\'s OWN template. `@ContentChild` accesses elements projected from the PARENT component via `<ng-content>`.' },
  { level: 'advanced', q: 'What is `static: true` in ViewChild?', a: 'If `true`, Angular resolves the query BEFORE change detection runs, meaning the element must not be inside an `*ngIf`. Useful when injecting the element in `ngOnInit`.' },
  { level: 'expert', q: 'How does Dependency Injection resolution work with `Host`, `Self`, `SkipSelf`, and `Optional` decorators?', a: '`@Optional`: Returns null if not found. `@Self`: Looks ONLY on the current component. `@SkipSelf`: Starts looking from the parent component. `@Host`: Stops looking when it reaches the host component (the boundary of the custom element).' },
  { level: 'advanced', q: 'What is a Router Outlet?', a: 'A directive (`<router-outlet>`) that acts as a placeholder where the router should display the components corresponding to the active route.' },
  { level: 'expert', q: 'What are intercepting routes?', a: 'Not native Angular terminology (that\'s Next.js). In Angular, we intercept HTTP requests via `HttpInterceptorFn`. It modifies outgoing requests (e.g., adding Auth tokens) or incoming responses (handling global errors).' },
  { level: 'advanced', q: 'What is a Resolver in routing?', a: 'A function that pre-fetches data before the route transition completes. The route will wait for the resolver observable to emit to prevent a blank UI.' },
  { level: 'advanced', q: 'What is an Entry Component?', a: 'A component loaded imperatively by code (like a Modal or Dialog) rather than declared in a template. In Ivy (v9+), you no longer need to declare them in `entryComponents` arrays.' },
  { level: 'advanced', q: 'What is APP_INITIALIZER?', a: 'An InjectionToken allowing you to run a function or Promise BEFORE the Angular app finishes bootstrapping. Great for loading initial config files.' },
  { level: 'expert', q: 'Explain ChangeDetectionStrategy.OnPush.', a: 'Tells Angular to only check the component when its `@Input()` references change, an event originates from within the component, an async pipe emits, or the new Signal state changes. Vastly improves performance.' },
  { level: 'advanced', q: 'What is a TrackBy function?', a: 'Used with `*ngFor` (or the `track` block in `@for`). It tells Angular how to uniquely identify items. If the array reference changes, Angular only updates DOM nodes that actually changed instead of destroying and recreating the whole list.' },
  { level: 'expert', q: 'How do you create a custom form control?', a: 'By implementing the `ControlValueAccessor` interface (`writeValue`, `registerOnChange`, `registerOnTouched`, `setDisabledState`) and providing it via the `NG_VALUE_ACCESSOR` token.' },
  { level: 'advanced', q: 'What is the ViewEncapsulation property?', a: 'It determines how styles are scoped to the component. `Emulated` (default) adds unique attributes to isolate styles. `None` applies them globally. `ShadowDom` uses native Shadow DOM.' },
  { level: 'expert', q: 'What is the purpose of `markForCheck()` vs `detectChanges()`?', a: '`markForCheck()` flags the component and all its ancestors to be checked in the NEXT normal change detection run. `detectChanges()` forces an immediate, synchronous check of the component and its children.' },
  { level: 'expert', q: 'What is `ngDoCheck`?', a: 'A lifecycle hook that triggers on EVERY change detection cycle, regardless of whether inputs changed. Highly dangerous to use because it executes very frequently; only use it for tracking complex internal object mutations if absolutely necessary.' },
  { level: 'advanced', q: 'How do you dynamically load a component at runtime?', a: 'Using `ViewContainerRef.createComponent()`, passing the imported component class. It allows injecting the component into a specific #placeholder in the DOM.' },
  { level: 'expert', q: 'What is `effect()` in Angular Signals?', a: 'An operation that runs when one or more signals it reads change. Useful for bridging signals to non-signal code (like DOM APIs, logging, or setting up RxJS subjects).' }
];
